CODE_EXAMPLE:
// Before
class Person {
  String getPhoneNumber() { return telephone.getPhoneNumber(); }
  Telephone telephone;
}

class Telephone {
  String areaCode;
  String number;
  String getPhoneNumber() { return areaCode + number; }
}

// After
class Person {
  String areaCode;
  String number;
  String getPhoneNumber() { return areaCode + number; }
}

UNIT_TEST_EXAMPLE:
@Test
public void testInlineClass() {
  Person person = new Person("415", "9999999");
  assertEquals("4159999999", person.getPhoneNumber());
}
